import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Installare Java su Windows","description":"Una guida passo per passo su come installare Java su Windows.","frontmatter":{"title":"Installare Java su Windows","description":"Una guida passo per passo su come installare Java su Windows.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"it_it/1.21.1/players/installing-java/windows.md","filePath":"versions/1.21.1/translated/it_it/players/installing-java/windows.md","lastUpdated":1761424914000}`);var l={name:`it_it/1.21.1/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installare Java su Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Installare Java su Windows”">​</a></h1><p>Questa guida ti spiegherà come installare Java 21 su Windows.</p><p>Il Launcher di Minecraft ha la sua versione di Java installata, quindi questa sezione è rilevante solo se vuoi usare l&#39;installer <code>.jar</code> di Fabric, oppure se vuoi usare il <code>.jar</code> del Server di Minecraft.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Controlla Se Java È Già Installato <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Controlla Se Java È Già Installato”">​</a></h2><p>Per controllare se Java è già installato devi prima aprire il prompt dei comandi.</p><p>Puoi farlo premendo <kbd>Win</kbd>+<kbd>R</kbd> e scrivendo <code>cmd.exe</code> nel riquadro che appare.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Dialogo Esegui su Windows che mostra &quot;cmd.exe&quot; scritto nella barra" loading="lazy"></p><p>Una volta aperto il prompt dei comandi, scrivi <code>java -version</code> e premi <kbd>Invio</kbd>.</p><p>Se il comando funziona correttamente, vedrai qualcosa come questo. Se il comando ha fallito, procedi con il prossimo passaggio.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Il prompt dei comandi con scritto &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Per usare Minecraft 1.21, ti servirà almeno Java 21 installato. Se questo comando mostra una versione inferiore a 21, allora dovrai aggiornare la versione di Java già esistente.</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. Scarica l&#39;Installer per Java 21 <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. Scarica l&#39;Installer per Java 21”">​</a></h2><p>Per installare Java 21, dovrai scaricare l&#39;installer da <a href="https://adoptium.net/en-GB/temurin/releases/?os=windows&amp;package=jdk&amp;version=21" target="_blank" rel="noreferrer">Adoptium</a>.</p><p>Dovrai scaricare la versione <code>Windows Installer (.msi)</code>:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="La pagina di download di Adoptium con Windows Installer (.msi) evidenziato" loading="lazy"></p><p>Dovresti scegliere <code>x86</code> se il tuo sistema operativo è a 32-bit, oppure <code>x64</code> se tuo sistema operativo è a 64-bit.</p><p>La maggior parte dei computer moderni ha un sistema operativo a 64-bit. Se non sei sicuro, prova a usare il download 64-bit.</p><h2 id="3-run-the-installer" tabindex="-1">3. Esegui l&#39;Installer! <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. Esegui l&#39;Installer!”">​</a></h2><p>Segui le istruzioni per installare Java 21. Quando arrivi a questa pagina, dovresti selezionare &quot;L&#39;intera funzionalità verrà installata sul disco rigido locale&quot; per le seguenti funzionalità:</p><ul><li><code>Imposta JAVA_HOME come variabile d&#39;ambiente</code> - Questo verrà aggiunto al tuo PATH.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Installer Java 21 con &quot;Set JAVAHOME variable&quot; e &quot;JavaSoft (Oracle) registry keys&quot; evidenziati" loading="lazy"></p><p>Quando hai finito, puoi cliccare su <code>Avanti</code> e continuare con l&#39;installazione.</p><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. Verifica che Java 21 Sia Installato <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. Verifica che Java 21 Sia Installato”">​</a></h2><p>Quando l&#39;installazione è stata completata, puoi verificare che Java 21 è installato aprendo il prompt dei comandi e scrivendo <code>java -version</code>.</p><p>Se il comando funziona correttamente, vedrai qualcosa simile a quello mostrato prima, dove è mostrata la versione di Java:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Il prompt dei comandi con scritto &quot;java -version&quot;" loading="lazy"></p><p>Se incontri dei problemi, sentiti libero di chiedere aiuto nel server <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> nel canale <code>#player-support</code>.</p>`,27)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};